function displayFilteredResults(documents) {
    const container = document.getElementById('filteredResults');

    // Clear previous content
    container.innerHTML = '';

    documents.forEach(document => {
        let riskClass = '';

        if (document.annuity_risk || document.time_to_expiry <= '6M') {
            riskClass = 'risk';
        }

        const card = `
            <div class="card ${riskClass}">
                <h4>${document.result_document_id} (Relevance Score: ${document.relevance_score})</h4>
                <p>Source: ${document.metadata.source}</p>
                <p>Expiration Date: ${document.metadata.expiration_date}</p>
                <p>Time to Expiry: ${document.time_to_expiry}</p>
                <p>Next Annuity Due Date: ${document.next_annuity_due_date ? document.next_annuity_due_date : 'N/A'}</p>
            </div>
        `;

        container.innerHTML += card;
    });
}
